--
-- Table structure for table `auction_sessions`
--

DROP TABLE IF EXISTS `auction_sessions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `auction_sessions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `product_id` bigint unsigned NOT NULL,
  `rule_id` bigint unsigned NOT NULL,
  `room_id` bigint unsigned NOT NULL,
  `status` enum('pending','active','ended','cancelled','unsold') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `current_price` decimal(12,2) NOT NULL DEFAULT '0.00',
  `winner_id` bigint unsigned DEFAULT NULL,
  `started_at` timestamp NULL DEFAULT NULL,
  `ended_at` timestamp NULL DEFAULT NULL,
  `extension_count` int NOT NULL DEFAULT '0',
  `version` int NOT NULL DEFAULT '0',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `order_created` tinyint(1) NOT NULL DEFAULT '1',
  `active_room_id` bigint unsigned DEFAULT NULL COMMENT 'Set to room_id when status is active/pending; NULL otherwise. Used for unique constraint.',
  PRIMARY KEY (`id`),
  UNIQUE KEY `idx_active_room_id` (`active_room_id`),
  KEY `auction_sessions_product_id_foreign` (`product_id`),
  KEY `auction_sessions_rule_id_foreign` (`rule_id`),
  KEY `auction_sessions_winner_id_foreign` (`winner_id`),
  KEY `idx_room_status` (`room_id`,`status`),
  CONSTRAINT `auction_sessions_product_id_foreign` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`),
  CONSTRAINT `auction_sessions_room_id_foreign` FOREIGN KEY (`room_id`) REFERENCES `live_rooms` (`id`),
  CONSTRAINT `auction_sessions_rule_id_foreign` FOREIGN KEY (`rule_id`) REFERENCES `auction_rules` (`id`),
  CONSTRAINT `auction_sessions_winner_id_foreign` FOREIGN KEY (`winner_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=239 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

