--
-- Table structure for table `bid_records`
--

DROP TABLE IF EXISTS `bid_records`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `bid_records` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `session_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned NOT NULL,
  `bid_amount` decimal(12,2) NOT NULL,
  `idempotency_key` varchar(64) COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),
  PRIMARY KEY (`id`),
  UNIQUE KEY `bid_records_idempotency_key_unique` (`idempotency_key`),
  KEY `bid_records_user_id_foreign` (`user_id`),
  KEY `bid_records_session_id_created_at_index` (`session_id`,`created_at`),
  CONSTRAINT `bid_records_session_id_foreign` FOREIGN KEY (`session_id`) REFERENCES `auction_sessions` (`id`),
  CONSTRAINT `bid_records_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=50117 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

